# Base module defining organisms hierarchy
# Provides the base Organism class and related utilities

class Organism:
    """Base class for all living organisms."""
    name: str
    age: int

    def __init__(self, name: str, age: int):
        self.name = name
        self.age = age

    @virtual
    def speak(self) -> str:
        return "..."

    @virtual
    def description(self) -> str:
        return f"{self.name} is {self.age} years old"


class Plant(Organism):
    """A plant organism - photosynthetic and rooted."""
    height_cm: int

    def __init__(self, name: str, age: int, height_cm: int):
        super().__init__(name, age)
        self.height_cm = height_cm

    @override
    def description(self) -> str:
        return f"{self.name} is a {self.age} year old plant, {self.height_cm}cm tall"


def classify_organism(org: Organism) -> str:
    """Helper function that works with any Organism type."""
    if isinstance(org, Plant):
        return "plant"
    return "animal"


def get_organism_summary(org: Organism) -> str:
    """Returns a formatted summary of any organism."""
    return f"[{classify_organism(org).upper()}] {org.description()}"

