# Module extending organisms with animal types
# Demonstrates importing and extending classes from another module

from organisms import Organism, classify_organism

class Animal(Organism):
    """Base class for animals."""
    species: str

    def __init__(self, name: str, age: int, species: str):
        super().__init__(name, age)
        self.species = species

    @override
    def description(self) -> str:
        base: str = super().description()
        return f"{base} ({self.species})"


class Dog(Animal):
    """A canine pet."""
    breed: str

    def __init__(self, name: str, age: int, breed: str):
        super().__init__(name, age, "Canis lupus familiaris")
        self.breed = breed

    @override
    def speak(self) -> str:
        return f"{self.name} says: Woof!"

    @override
    def description(self) -> str:
        return f"{self.name} is a {self.age} year old {self.breed}"


class Cat(Animal):
    """A feline pet."""
    lives_remaining: int

    def __init__(self, name: str, age: int):
        super().__init__(name, age, "Felis catus")
        self.lives_remaining = 9

    @override
    def speak(self) -> str:
        return f"{self.name} says: Meow!"

    def lose_life(self) -> int:
        if self.lives_remaining > 0:
            self.lives_remaining = self.lives_remaining - 1
        return self.lives_remaining


class Bird(Animal):
    """A flying animal."""
    can_fly: bool

    def __init__(self, name: str, age: int, can_fly: bool):
        super().__init__(name, age, "Aves")
        self.can_fly = can_fly

    @override
    def speak(self) -> str:
        return f"{self.name} says: Tweet!"


def create_zoo() -> list[Organism]:
    """Factory function returning a list of organisms."""
    zoo: list[Organism] = []
    zoo.append(Dog("Rex", 5, "German Shepherd"))
    zoo.append(Cat("Whiskers", 3))
    zoo.append(Bird("Polly", 2, True))
    return zoo
